item.aggregated_output:
 1	{# Single proposal row, rendered standalone for HTMX swaps and inline by planner_claim.html. #}
 2	{% set row = row_state if row_state is defined else {"slug":"","priority":"1.0","parent_commits":"","rationale":""} %}
 3	{% set row_errs = row_errs if row_errs is defined else {} %}
 4	<div class="proposal-row" data-row-index="{{ i }}">
 5	    <h3>row {{ i + 1 }}</h3>
 6	    <label>slug
 7	        <input type="text" name="slug" value="{{ row.slug }}">
 8	        {% if row_errs.get("slug") %}<span class="field-error">{{ row_errs["slug"] }}</span>{% endif %}
 9	    </label>
10	    <label>priority
11	        <input type="text" name="priority" value="{{ row.priority }}">
12	        {% if row_errs.get("priority") %}<span class="field-error">{{ row_errs["priority"] }}</span>{% endif %}
13	    </label>
14	    <label>parent commit SHAs (comma-separated)
15	        <input type="text" name="parent_commits" value="{{ row.parent_commits }}">
16	        {% if row_errs.get("parent_commits") %}<span class="field-error">{{ row_errs["parent_commits"] }}</span>{% endif %}
17	    </label>
18	    <label>rationale (markdown)
19	        <textarea name="rationale" rows="6">{{ row.rationale }}</textarea>
20	        {% if row_errs.get("rationale") %}<span class="field-error">{{ row_errs["rationale"] }}</span>{% endif %}
21	    </label>
22	</div>
